/*
带权边并查集
设底部箱子是根节点
dist[i]为i到它父亲有多少在它地下的箱子
siz[i]为以i为根节点的子树的大小
递归路径压缩
*/
#include <bits/stdc++.h>
using namespace std;
const int N=3e4+4;
int n,f[N],dist[N],siz[N];
int father(int x){
    if(f[x]!=x){
        int fa=f[x];
        f[x]=father(f[x]);
        dist[x]+=dist[fa];
    }
    return f[x];
}
void merge(int x,int y){
    int fx=father(x),fy=father(y);
    if(fx!=fy)
        f[fx]=fy,dist[fx]=siz[fy],siz[fy]+=siz[fx];
}
int main(){
    scanf("%d",&n);
    for(int i=1;i<=3e4;i++)
        f[i]=i,siz[i]=1;
    while(n--){
        char op;
        int x,y;
        cin>>op;
        if(op=='M'){
            scanf("%d%d",&x,&y);
            merge(x,y);
        }else{
            scanf("%d",&x);
            father(x);
            printf("%d\n",dist[x]);
        }
    }
    return 0;
}
